import c4d
doc = c4d.documents.GetActiveDocument()
for n in ['DetCube', 'DetSphere', 'DetLight']:
    o = doc.SearchObject(n)
    if o: o.Remove()
for name, kind in [('DetCube', c4d.Ocube), ('DetSphere', c4d.Osphere), ('DetLight', c4d.Olight)]:
    o = c4d.BaseObject(kind); o.SetName(name)
    if kind == c4d.Ocube:
        o.SetAbsPos(c4d.Vector(-100, 0, 0))
    elif kind == c4d.Osphere:
        o.SetAbsPos(c4d.Vector(100, 0, 0))
    doc.InsertObject(o)
c4d.EventAdd()
print('determinism scene built')

import c4d
doc = c4d.documents.GetActiveDocument()
import gc
for obj in gc.get_objects():
    if type(obj).__name__ == 'C4DSocketServer':
        srv = obj; break
cache = srv._SNAPSHOT_CACHE
ids = list(cache.keys())
print(f'cache has {len(ids)} snapshots; testing last 2: {ids[-2:]}')
if len(ids) < 2:
    print('NEED 2 SNAPSHOTS')
else:
    s1 = cache[ids[-2]]
    s2 = cache[ids[-1]]
    s1_objs = {o.get('guid'): {k: v for k, v in o.items() if k not in ('guid',)} for o in s1.get('objects', [])}
    s2_objs = {o.get('guid'): {k: v for k, v in o.items() if k not in ('guid',)} for o in s2.get('objects', [])}
    same = s1_objs == s2_objs
    print(f'snapshot objects byte-equal (modulo guid): {same}')
    if not same:
        diff_keys = set(s1_objs) ^ set(s2_objs)
        print(f'  guid set diff: {diff_keys}')
        for g in (set(s1_objs) & set(s2_objs)):
            if s1_objs[g] != s2_objs[g]:
                for k in set(s1_objs[g]) | set(s2_objs[g]):
                    if s1_objs[g].get(k) != s2_objs[g].get(k):
                        print(f'  guid={g} field={k}: {s1_objs[g].get(k)} -> {s2_objs[g].get(k)}')
